import outlines
from outlines.prompts import register_filter, unregister_filter

register_filter('shout', lambda s: s.upper() + '!')

@outlines.prompt
def greet(text):
    '''{{ text | shout }}'''

print(greet('hello'))

@outlines.prompt(filters={'reverse': lambda s: s[::-1]})
def combo(text):
    '''{{ text | shout }} {{ text | reverse }}'''

print(combo('hi'))

unregister_filter('shout')
try:
    greet('hello')
    print('ERROR: should have failed')
except Exception as e:
    print('OK, unregister works:', type(e).__name__)
"
